import { getDurationContent } from './get-duration-content.js';
import { getShownHeaderText } from './get-shown-header-text.js';
import { getValue } from './get-value.js';
import type { TruncationMode } from '../../../../../../../typography/text-ellipsis/TextEllipsis.js';
import { useDefaultLabels } from '../../../hooks/useDefaultLabels.js';
import { HeaderData } from '../../../types.js';
import { calculateTotalWidth500 } from '../../../utils/width-calculation.js';
import { HeaderValueFormatter } from '../types/header.js';

const buildContent = (
  formattedValue: string | undefined,
  headerLabel: string | undefined,
): string => {
  if (!formattedValue) {
    return '';
  }
  return headerLabel ? `${headerLabel}: ${formattedValue}` : formattedValue;
};

export const computeHeaderDisplay = ({
  header,
  label,
  duration,
  formatStrategy,
  labelFor,
  isSingleLine,
  isTruncationEnd,
  availableWidth,
  showedLines,
  truncationMode,
  showRangeDuration,
}: {
  header: HeaderData | undefined;
  label: string | undefined;
  duration: string | undefined;
  formatStrategy: HeaderValueFormatter;
  labelFor: ReturnType<typeof useDefaultLabels>;
  isSingleLine: boolean;
  isTruncationEnd: boolean;
  availableWidth: number;
  showedLines: number;
  truncationMode: TruncationMode;
  showRangeDuration: boolean;
}) => {
  const value = getValue(header);
  const formattedValue = formatStrategy(value);
  const headerLabel = labelFor?.('headerLabel', label);
  const content = buildContent(formattedValue, headerLabel);

  const totalTextWidth = calculateTotalWidth500(content);
  const durationContent =
    duration ?? getDurationContent(showRangeDuration, header);
  const durationSuffix = durationContent ? ` (${durationContent})` : '';
  const durationSuffixWidth = durationSuffix
    ? calculateTotalWidth500(durationSuffix)
    : 0;

  const isJsTruncation = isSingleLine || !isTruncationEnd;
  const effectiveWidth =
    isJsTruncation && durationSuffixWidth > 0
      ? availableWidth - durationSuffixWidth
      : availableWidth;

  const shownText = getShownHeaderText(
    content,
    isSingleLine,
    isTruncationEnd,
    effectiveWidth,
    showedLines,
    truncationMode,
  );

  const isMultiLineCssClamped =
    !isSingleLine &&
    isTruncationEnd &&
    Math.ceil((totalTextWidth + durationSuffixWidth) / availableWidth) >
      showedLines;

  return {
    content,
    totalTextWidth,
    shownText,
    isTruncated: isMultiLineCssClamped || shownText !== content,
    durationContent,
    durationSuffix,
  };
};
